+            "code": code,
+            "state": state,
+            "redirect_uri": ANTHROPIC_OAUTH_REDIRECT_URI,
+            "code_verifier": verifier,
+        }))
+        .send()
+        .await
+        .map_err(|e| Error::auth(format!("Token exchange failed: {e}")))?;
+
